// Models/Review.cs
public class Review
{
    public int ReviewId { get; set; }
    public string ProductId { get; set; }
    public string Author { get; set; }
    public string Content { get; set; }
}

// Controllers/ProductController.cs
public class ProductController : Controller
{
    private readonly YourDbContext _context;

    public ProductController(YourDbContext context)
    {
        _context = context;
    }

    public IActionResult Product(string productId)
    {
        var product = _context.Products.Find(productId);
        var reviews = _context.Reviews.Where(r => r.ProductId == productId).ToList();
        return View(new ProductViewModel { Product = product, Reviews = reviews });
    }
}

// Views/Product/Product.cshtml
@model ProductViewModel

<h1>@Model.Product.Name</h1>

<ul>
    @foreach (var review in Model.Reviews)
    {
        <li>
            <strong>@review.Author:</strong>
            @Html.Raw(review.Content)
        </li>
    }
</ul>
